'''
当你遍历某个对象（如类文件对象）并为每个项执行 yield 时，
也可以使用 yield from 直接 yield 每个项，从而跳过 for 循环。

这不是 FastAPI 特有的，只是 Python 的语法，但这是一个很有用的技巧
'''
import uvicorn
import base64
from io import BytesIO
from fastapi import FastAPI
from fastapi.responses import StreamingResponse
from collections.abc import Iterable

app = FastAPI()

def read_image(image_bytes):
    return BytesIO(base64.b64decode(""))

class PNGStreamingResponse(StreamingResponse):
    media_type = "image/png"



@app.get("/image/stream-no-async-yield-from", response_class=PNGStreamingResponse)
def stream_image_no_async_yield_from() -> Iterable[bytes]:
    with read_image() as image_file:
        yield from image_file